var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"안녕? 난 하트베리의 차기 리더, 루미야!","JPN":"みんな、元気してる？　アタシはハートベリーの次期リーダー、ルミよ！","ENG":"Hi! I'm Lumi, the next leader of HRT Berry!","TWN":"大家好嗎？我是愛心莓果的下一任隊長，魯米哟！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"방송이 준비되는 동안 시청자 여러분과 짧게 질답시간을 가져볼게!","JPN":"配信開始までの間に、視聴者のみんなからの\\n質問に答えようと思うの！","ENG":"We'll do a little Q & A session with our viewers while they set up the show!","TWN":"趁播出還在準備的期間，就讓我們和觀眾朋友進行短暫的問答時間吧！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"어머, <color=#ffd34c>MAYA6G3</color>님! 하트베리 멤버들 중에서 루미를 제일 좋아한다고? 고마워~","JPN":"あら、<color=#ffd34c>MAYA6G3</color>さん！　ハートベリーの\\nメンバーで最推しはルミなの？　ありがとぉ～♪","ENG":"Oh my, <color=#ffd34c>MAYA6G3</color>! I'm your favorite member in HRT Berry? Thanks!","TWN":"哇哦， <color=#ffd34c>MAYA6G3</color>先生！你說在愛心莓果中最喜歡魯米嗎？謝謝你～"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_COIN"},{"id":"L6_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"말이 나와서 말인데, 솔직히 나만큼 개성 넘치고 매력 넘치는 아이돌 없지 않아?","JPN":"勢いで聞いちゃうけど、正直言ってアタシほど個性的で魅力満点なアイドルっていないわよね？","ENG":"Speaking of which, I'm cuter and more adorable than any pop stars out there, no?","TWN":"說真的，像我這樣充滿個性和魅力的偶像，肯定不會有第二個了吧？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......겁 없는 거 하나는 인정이라고?","JPN":"……はぁ？　勇気だけは一人前ですって？","ENG":"I sure am over-confident, you say?","TWN":"……你說你只承認我天不怕地不怕這一點嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"너무해~","JPN":"ひっど～い。","ENG":"Aw, come on!","TWN":"好過分唷～"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......응? 내 예전 오디션영상 봤어?","JPN":"……えっ？　アタシの昔のオーディション動画を観たですって？","ENG":"Huh? You saw my old audition footage?","TWN":"……嗯？你看過我以前試鏡的影片嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"나도 그런 게 남아있는 줄 몰랐는데, 어떻게 찾았대?","JPN":"そんなものが未だに残っていたのね。どうやって見つけたの？","ENG":"I didn't even know they still had those around. How did you find it?","TWN":"這影片竟然還在喔，你是怎麼找到的呀？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"후후~ 봤다면 알겠지만, 난 춤 실력도 꽤 수준이 높거든.","JPN":"ふふ、観たなら話が早いけど、アタシ、ダンスの実力も抜群なのよね。","ENG":"Heh, as you may have seen, I'm a great dancer too.","TWN":"呵呵～ 你看了應該就知道，我的跳舞實力挺高吧。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"당연히 그쪽 분야로 진출했다면 날 모셔가려는 기획사가 널리고 널렸었겠지만 말이지......","JPN":"もちろん、そっちの分野に進んでいたら、アタシ目当てのスカウトが行列をなしたと思うけど……","ENG":"If I decided to become a dancing star, I'm sure tons of agencies would've raced to recruit me...","TWN":"當然，如果我繼續往那個方向努力，一定會有很多公司想要我吧……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"그 취미는 잠시 접어두기로 했어. 능력 있는 자로서의 소명의식 같은 거랄까?","JPN":"その趣味はひとまず置いておくことにしたわ。\\n優れた者としての使命感とでも言うのかしら。","ENG":"But I decided to put that hobby aside for now. I guess you could say I'm answering my call as a gifted person.","TWN":"但我還是決定暫時把這個愛好放一邊，這就是身為有能力者的使命感嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"어차피 춤은 연습만 하면 누구나 출 수 있는 거잖아?","JPN":"ダンスって、猛練習すれば誰でも踊れるようになるじゃない？","ENG":"Besides, anyone can dance well with enough practice!","TWN":"反正舞蹈這種東西只要你願意學，誰都可以跳吧？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"하지만 아름다운 강자가 전장을 누비며 침식체를 사냥하는 멋진 장면은!","JPN":"でもね。美しき狩人が戦場を駆け抜けて、侵食体を鮮やかに仕留める！","ENG":"But it's not every day you see a gorgeous Counter hunt down C.O.s!","TWN":"但是美麗的強者穿梭於戰場，狩獵侵蝕體的帥氣場景！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"오로지, 나 같은 미모의 카운터만이 연출할 수 있는 모습 아니겠어?","JPN":"そういう名シーンって、アタシのような美貌の\\nカウンターにしか演じられないでしょう？","ENG":"Only a beauty like me could pull that off!","TWN":"就只有我這樣美貌的制裁者，才能有這樣的演出吧？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"응? 그렇게 강하면서 왜 리더는 못 한......","JPN":"えっ？　そんなに強いなら何でリーダーになれないのかって……","ENG":"Huh? How come I'm not the leader if I'm that strong?","TWN":"嗯？既然我這麼厲害，那為什麼不是隊長……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......앗차, 손이 미끄러졌네. 미안~ 채팅금지는 다시 풀어줄게.","JPN":"……あらいけない。アタシったら手がすべっちゃった。\\nごめんね～チャット禁止は解除したげるね。","ENG":"Oops! My finger slipped. Sorry, I'll unblock you from chat in a moment...","TWN":"……哎呀，我手滑了。抱歉啦～我會再幫你解BAN的。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"벌써 방송 준비가 끝났다나 봐!","JPN":"あっ、もう配信の準備が終わったみたい！","ENG":"Oh, it sounds like the show is ready to go!","TWN":"看來直播準備已經結束了！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"대화를 나눌 시간이 짧아서 아쉽다, 그치?","JPN":"ちょっとしか話せなくて名残り惜しいわ。みんなもそう思うでしょ？","ENG":"Too bad we don't get much time to talk, huh?","TWN":"歡樂的時光總是這麼短暫，對吧？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"그럼 오늘도 우리 멤버들에게 많은 응원 부탁해!","JPN":"それじゃ、今日もうちのメンバーたちにたくさんの応援をよろしくね！","ENG":"Alright, please cheer for us again today!","TWN":"那希望大家今後也能多多支持我們的團員！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"바이바이~","JPN":"バイバ～イ♪","ENG":"Byeee!","TWN":"掰掰~"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};